const results = $json.data?.Get?.MitreAttackNomic || [];

return results.map(r => ({
  json: {
    behavior: $json.behavior,
    attack_id: r.attack_id,
    name: r.name,
    tactic: r.tactic,
    content: r.content
  }
}));

const events = $json.events || [];

let keyEvents = [];
let lastAction = null;

events.forEach((e, idx) => {
  if (idx === 0 || idx === events.length - 1 || e.action !== lastAction) {
    keyEvents.push(
      `${e.timestamp_human} EventID=${e.action} ${e.details.split("EventID=")[1]}`
    );
    lastAction = e.action;
  }
});

return [
  {
    json: {
      key_events: keyEvents
    }
  }
];

let logs = Array.isArray($json) ? $json : $input.all().map(item => item.json);
if (!logs.length) return [{ json: { behaviors: [], message: "No logs provided" } }];

function toTime(ts) { return new Date(ts).getTime(); }

// Organize by IP and by User
const byIP = {}, byUser = {};
for (const log of logs) {
    const ip = log.IpAddress;
    const user = log.TargetUserName;
    if (!ip) continue;

    if (!byIP[ip]) byIP[ip] = [];
    byIP[ip].push(log);

    if (!byUser[user]) byUser[user] = [];
    byUser[user].push(log);
}

// ===== Define dynamic behavior rules =====
const rules = [
    {
        name: "Brute-force login attempts",
        type: "ip",
        condition: (events) => {
            for (let i = 0; i < events.length; i++) {
                const start = toTime(events[i].timestamp);
                const window = events.filter(e =>
                    e.EventID === "4625" &&
                    toTime(e.timestamp) >= start &&
                    toTime(e.timestamp) <= start + (5 * 60 * 1000)
                );
                if (window.length >= 5) return true;
            }
            return false;
        },
        message: ip => `Brute-force login attempts from IP ${ip}`
    },
    {
        name: "Success after repeated failures",
        type: "ip",
        condition: (events) => {
            let failCount = 0;
            for (const e of events) {
                if (e.EventID === "4625") failCount++;
                if (e.EventID === "4624" && failCount >= 5) return true;
            }
            return false;
        },
        message: ip => `Successful login after repeated failures from IP ${ip}`
    },
    {
        name: "Multiple IPs per user",
        type: "user",
        condition: (events) => new Set(events.map(e => e.IpAddress).filter(Boolean)).size >= 2,
        message: user => `User ${user} logged in from multiple IP addresses`
    },
    {
        name: "Privileged login after authentication",
        type: "user",
        condition: (events) => {
            for (let i = 0; i < events.length - 1; i++) {
                if (events[i].EventID === "4624" && events[i+1].EventID === "4672") return true;
            }
            return false;
        },
        message: user => `Privileged login following authentication for user ${user}`
    },
    {
        name: "Explicit credential usage",
        type: "log",
        condition: (log) => log.EventID === "4648",
        message: (log) => `Explicit credential usage detected for user ${log.TargetUserName}`
    }
];

// ===== Evaluate rules dynamically =====
const behaviors = [];

for (const rule of rules) {
    if (rule.type === "ip") {
        for (const ip in byIP) {
            const events = byIP[ip].sort((a,b) => toTime(a.timestamp) - toTime(b.timestamp));
            if (rule.condition(events)) behaviors.push(rule.message(ip));
        }
    } else if (rule.type === "user") {
        for (const user in byUser) {
            const events = byUser[user].sort((a,b) => toTime(a.timestamp) - toTime(b.timestamp));
            if (rule.condition(events)) behaviors.push(rule.message(user));
        }
    } else if (rule.type === "log") {
        for (const log of logs) {
            if (rule.condition(log)) behaviors.push(rule.message(log));
        }
    }
}

// Deduplicate
const uniqueBehaviors = [...new Set(behaviors)];

// Output
return [{ json: { behaviors: uniqueBehaviors, logsCount: logs.length } }];

const all = $input.all();

return [{
  json: {
    mitre: all.map(item => item.json)
  }
}];

const mitreItems = $json.mitre || [];

const behaviorMap = new Map();

// Loop over each Mitre item
for (const item of mitreItems) {
  const behaviorName = item.behavior || "Unknown Behavior";

  // If behavior not yet in map, add it
  if (!behaviorMap.has(behaviorName)) {
    behaviorMap.set(behaviorName, {
      behavior: behaviorName,
      mitre: []
    });
  }

  // Push the Mitre technique under the correct behavior
  behaviorMap.get(behaviorName).mitre.push({
    attack_id: item.attack_id,
    name: item.name,
    tactic: item.tactic,
    content: item.content
  });
}

// Convert map values to array
const groupedBehaviors = Array.from(behaviorMap.values());

return [{
  json: {
    behaviors: groupedBehaviors
  }
}];

const data = $json;

// Flatten MITRE
const flatMitre = (data.mitre || []).flatMap(m => m.mitre || []);
const validMitre = flatMitre.filter(m => m.attack_id && m.name);

// Sections
const ips = data.ips?.length ? data.ips.join(", ") : "Not Provided";
const users = data.users?.length ? data.users.join(", ") : "Not Provided";
const earliest = data.earliest || "Not Provided";

// Normalize behavior(s)
const behaviorsArray = data.behaviors || (data.behavior ? [data.behavior] : []);
const behaviors = behaviorsArray.length
  ? behaviorsArray.map((b, i) => `${i+1}. ${b}`).join("\n")
  : "Not Provided";

const mitre = validMitre.length
  ? validMitre.map((m, i) => `${i+1}. ${m.attack_id} - ${m.name}`).join("\n")
  : "Not Found";

// LLM OUTPUT PARSING
const descriptionMatch = data.llm_output?.match(/\*\*Description of Events\*\*([\s\S]*?)\*\*Remediation Steps\*\*/);
const remediationMatch = data.llm_output?.match(/\*\*Remediation Steps\*\*([\s\S]*)/);

const description = descriptionMatch
  ? descriptionMatch[1].trim()
  : "Not Provided";

const remediation = remediationMatch
  ? remediationMatch[1].trim()
  : "Not Provided";

// Key Events as Appendix A
const appendixA = data.key_events?.length
  ? data.key_events.map((ke, i) => `${i+1}. ${ke}`).join("\n")
  : "Not Provided";

// FINAL REPORT (single object)
const report_text = `
Incident Report

Reporter Information:
Name: Not Provided
Title: Cybersecurity Incident Investigation Assistant
Report Date: Not Provided
Incident Number: Not Provided

Incident Overview:
Date of Incident: ${earliest}
Type: Not Provided
Impact Level: Not Provided

Network Details:
Attacker IP Address(es): ${ips}
Victim User(s): ${users}

Observed Behaviors:
${behaviors}

Relevant MITRE ATT&CK Techniques:
${mitre}

Description of Events:
${description}

Remediation Steps:
${remediation}

Appendix A: Key Events
${appendixA}
`;

return [{ json: { report_text } }];

const text = $json.text || $json.output || $json.response || $json.llm_output || "";

// Extract Description (stop at Remediation Steps or end of text)
const descriptionMatch = text.match(
  /Description of Events:?\s*([\s\S]*?)(?:Remediation Steps:?|$)/i
);

// Extract Remediation (optional)
const remediationMatch = text.match(
  /Remediation Steps:?\s*([\s\S]*)/i
);

const description = descriptionMatch ? descriptionMatch[1].trim() : "Not Provided";
const remediation = remediationMatch ? remediationMatch[1].trim() : "Not Provided";

return [{
  json: {
    description,
    remediation
  }
}];

const data = $json;

// =======================
// BASIC SECTIONS
// =======================
const ips = data.ips?.length ? data.ips.join(", ") : "Not Provided";
const users = data.users?.length ? data.users.join(", ") : "Not Provided";

// Human-readable date (fallback safe)
const earliestRaw = data.earliest;
const earliest = earliestRaw
  ? new Date(earliestRaw).toLocaleString("en-US", {
      weekday: "short",
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit"
    })
  : "Not Provided";

// LLM output
const description = data.description || "Not Provided";
const remediation = data.remediation || "Not Provided";

// =======================
// BEHAVIORS 
// =======================
const behaviorsArray = data.behaviors || [];

const behaviors = behaviorsArray.length
  ? behaviorsArray.map((b, i) => `${i+1}. ${b.behavior}`).join("\n")
  : "Not Provided";

// =======================
// MITRE (GROUPED BY BEHAVIOR)
// =======================
const mitreSet = new Map();

for (const b of behaviorsArray) {
  for (const m of (b.mitre || [])) {
    if (m.attack_id && !mitreSet.has(m.attack_id)) {
      mitreSet.set(m.attack_id, `${m.attack_id} - ${m.name}`);
    }
  }
}

const mitre = mitreSet.size
  ? Array.from(mitreSet.values()).map((m, i) => `${i+1}. ${m}`).join("\n")
  : "Not Found";

// =======================
// DETAILED MITRE PER BEHAVIOR 
// =======================
const mitreByBehavior = behaviorsArray.length
  ? behaviorsArray.map((b, i) => {
      const techniques = (b.mitre || [])
        .map(m => `${m.attack_id} - ${m.name}`)
        .join(", ") || "None";

      return `${i+1}. ${b.behavior}\n   Techniques: ${techniques}`;
    }).join("\n\n")
  : "Not Provided";

// =======================
// EVENTS 
// =======================
const events = data.events?.length
  ? data.events.map((e, i) => {
      const timestamp = e.timestamp_human || e.timestamp || "Not Provided";
      const eventType = e.event_type || "Not Provided";

      const details = e.details
        || (e.expert_messages?.map(m =>
            `${m.message} (sev ${m.severity_normalized})`
          ).join("; "))
        || "Not Provided";

      return `${i+1}. ${timestamp} | ${eventType} | ${details}`;
    }).join("\n")
  : "Not Provided";

// =======================
// APPENDIX A (KEY EVENTS)
// =======================
const appendixA = data.key_events?.length
  ? data.key_events.map((ke, i) => `${i+1}. ${ke}`).join("\n")
  : "Not Provided";

// =======================
// FILENAME
// =======================
const original_filename =
  data.original_filename ||
  data.events?.[0]?.original_filename ||
  "Not Provided";

// =======================
// FINAL REPORT
// =======================
const report_text = `
Incident Report

Reporter Information:
Name: Not Provided
Title: Cybersecurity Incident Investigation Assistant
Report Date: ${new Date().toLocaleString()}
Incident Number: Not Provided
Log Analyzed: ${original_filename}

Incident Overview:
Date of Incident: ${earliest}
Type: Not Provided
Impact Level: Not Provided

Network Details:
Attacker IP Address(es): ${ips}
Victim User(s): ${users}

Behavior-to-Technique Mapping:
${mitreByBehavior}

Description of Events:
${description}

Remediation Steps:
${remediation}

Appendix A: Key Events
${appendixA}
`;

return [{
  json: {
    report_text,
    original_filename
  }
}];

const behaviors = $json.behaviors || $json.events?.map(e => e.event_type) || [];

const simplifiedBehaviors = behaviors.map(b => {
  // Remove IP addresses
  let s = b.replace(/\b\d{1,3}(?:\.\d{1,3}){3}\b/g, "");
  // Remove ports
  s = s.replace(/port\s+\d+/gi, "");
  // Remove extra whitespace
  s = s.replace(/\s+/g, " ").trim();
  return s;
});

// Deduplicate
const uniqueBehaviors = [...new Set(simplifiedBehaviors)];

return [{
  json: {
    behaviors: uniqueBehaviors
  }
}];
